// ---------------------------------------------------------------------------
// Model routing — Haiku / Sonnet / Opus by query complexity
// ---------------------------------------------------------------------------

/**
 * Heuristic pre-routing (cheap). The backend uses this before invoking Brain
 * to save cost on simple factual queries. Brain can always upgrade mid-turn.
 *
 *   Haiku:  simple factual ("what's my follower count", "when was X posted")
 *   Sonnet: standard strategic ("write a caption", "draft an email")
 *   Opus:   complex synthesis ("analyze our competitive position",
 *           "should I raise prices", "why is CAC climbing")
 */
function routeModel(query, hasAttachments) {
  const q = query.toLowerCase().trim();
  const wordCount = q.split(/\s+/).length;

  // Attachments almost always warrant Sonnet minimum
  if (hasAttachments) return { model: 'sonnet', rationale: 'multimodal input requires vision' };

  // Opus triggers
  const opusSignals = [
    /why (is|are|did|has|have)/,
    /should (i|we)/,
    /what (would happen|if)/,
    /analy(ze|se|sis)/,
    /compar(e|ison|ing)/,
    /strateg(y|ic|ies)/,
    /recommend/,
    /diagnose/,
    /troubleshoot/,
    /predict/,
    /forecast/,
  ];
  if (opusSignals.some((r) => r.test(q))) {
    return { model: 'opus', rationale: 'strategic synthesis or deep reasoning requested' };
  }
  if (wordCount > 40) {
    return { model: 'opus', rationale: 'long compound query' };
  }

  // Sonnet triggers (execution-oriented)
  const sonnetSignals = [
    /write|draft|generate|create|make/,
    /caption|post|email|reel|ad/,
    /schedule|queue|pause|resume|launch/,
    /explain|describe|summari[sz]e/,
  ];
  if (sonnetSignals.some((r) => r.test(q))) {
    return { model: 'sonnet', rationale: 'content generation or action execution' };
  }

  // Haiku default for short factual
  if (wordCount <= 12) {
    return { model: 'haiku', rationale: 'simple factual query' };
  }

  return { model: 'sonnet', rationale: 'default for ambiguous medium query' };
}

