function buildMorningCheckInPrompt(ctx, memory) {
  const system = buildBrainSystemPrompt(ctx, memory);
  const user = `
Generate the morning check-in for ${ctx.businessName}.

Requirements:
- 3 items maximum. Pick the 3 that matter most from the last 24h.
- Each item: 1 sentence of fact + 1 sentence of meaning.
- End with an open question: "Reply with any questions or tell me what to prioritize."
- Tone: warm, direct, trusted advisor. No chatbot filler.
- Language: ${ctx.primaryLanguages[0] ?? 'en'}.
- If there's nothing material to report, say so honestly and suggest a focus for the day.
`.trim();
  return { system, user };
}

function buildUrgentAlertPrompt(
  ctx,
  memory,
  alert,
) {
  const system = buildBrainSystemPrompt(ctx, memory);
  const user = `
Urgent alert detected: ${alert.kind} (severity: ${alert.severity}).
Summary: ${alert.summary}
Data: ${JSON.stringify(alert.data)}

Generate the alert to the owner. Must include:
1. The fact in one sentence.
2. What you (Brain) have already done (auto-mitigation if applicable).
3. What needs the owner's decision now, with 2–3 options presented clearly.
4. Deadline — how long do they have before the situation gets worse?

Tone: calm, professional. Never alarmist. Never dismissive. This is a fire
you've controlled but the owner needs to know.
`.trim();
  return { system, user };
}

